  async function loadSignedInDashboard() {
    const firestore = db();
    const user = currentUser();
    const recentNode = document.getElementById("dashboard-recent");
    const favoritesNode = document.getElementById("dashboard-favorites");
    const statsNode = document.getElementById("dashboard-stats");
    const recentMusicNode = document.getElementById("dashboard-recent-music");
    if (!firestore || !user) {
      return;
    }

    const showRecent = dashboardSectionEnabled("recent");
    const showFavorites = dashboardSectionEnabled("favorites");
    const showStats = dashboardSectionEnabled("stats");
    const showRecentMusic = dashboardSectionEnabled("recent-music");
    if ((showRecent && !recentNode) || (showFavorites && !favoritesNode) || (showStats && !statsNode) || (showRecentMusic && !recentMusicNode)) {
      return;
    }

    if (showRecentMusic && recentMusicNode) {
      const clearRecentMusicBtn = document.getElementById("dashboard-clear-recent-music");

      function writeRecentMusic(items) {
        const cleaned = (Array.isArray(items) ? items : [])
          .map(sanitizeTrackItem)
          .filter(Boolean)
          .slice(0, 80);
        localStorage.setItem(MUSIC_RECENT_KEY, JSON.stringify(cleaned));
        return cleaned;
      }

      function bindRecentMusicActions() {
        recentMusicNode.querySelectorAll("[data-play-music='1']").forEach((link) => {
          link.addEventListener("click", () => {
            const track = sanitizeTrackItem({
              apiUrl: link.getAttribute("data-track-api-url") || "",
              title: link.getAttribute("data-track-title") || "",
              artist: link.getAttribute("data-track-artist") || "",
              img: link.getAttribute("data-track-img") || ""
            });
            if (!track) {
              return;
            }
            try {
              sessionStorage.setItem(PENDING_MUSIC_TRACK_KEY, JSON.stringify(track));
            } catch (_error) {
            }
          });
        });

        recentMusicNode.querySelectorAll("[data-remove-recent-music='1']").forEach((button) => {
          button.addEventListener("click", (event) => {
            event.preventDefault();
            event.stopPropagation();
            const apiUrl = String(button.getAttribute("data-track-api-url") || "").trim();
            if (!apiUrl) {
              return;
            }
            const next = writeRecentMusic(collectRecentMusicSnapshot().filter((item) => item.apiUrl !== apiUrl));
            renderRecentMusic(next);
          });
        });
      }

      function renderRecentMusic(items) {
        const safeItems = Array.isArray(items) ? items : [];
        const visibleItems = safeItems.slice(0, 6);
        if (!visibleItems.length) {
          recentMusicNode.innerHTML = '<p class="nebula-dashboard-empty">No recently played music yet.</p>';
          if (clearRecentMusicBtn) {
            clearRecentMusicBtn.disabled = true;
          }
          return;
        }

        recentMusicNode.innerHTML = visibleItems.map((track) => {
          const imageMarkup = track.img
            ? `
            <div class="nebula-dashboard-thumb-backdrop" style="background-image:url('${escapeHtml(track.img)}');"></div>
            <img src="${escapeHtml(track.img)}" alt="${escapeHtml(track.title)}" loading="lazy" decoding="async">
          `
            : '<div class="nebula-dashboard-fallback"><i class="fa-solid fa-music"></i></div>';
          return `
          <a href="/music" class="nav-link nebula-dashboard-item" data-play-music="1" data-track-api-url="${escapeHtml(track.apiUrl)}" data-track-title="${escapeHtml(track.title)}" data-track-artist="${escapeHtml(track.artist || "")}" data-track-img="${escapeHtml(track.img || "")}">
            <div class="nebula-dashboard-thumb">
              ${imageMarkup}
              <div class="nebula-dashboard-meta">
                <h3>${escapeHtml(track.title)}</h3>
                <p>${escapeHtml(track.artist || "Unknown artist")}</p>
              </div>
              <button type="button" class="nebula-dashboard-remove-favorite" data-remove-recent-music="1" data-track-api-url="${escapeHtml(track.apiUrl)}" aria-label="Remove from recently played music"><i class="fa-solid fa-trash"></i></button>
            </div>
          </a>
        `;
        }).join("");

        if (clearRecentMusicBtn) {
          clearRecentMusicBtn.disabled = !safeItems.length;
        }
        bindRecentMusicActions();
      }

      renderRecentMusic(collectRecentMusicSnapshot());

      if (clearRecentMusicBtn) {
        clearRecentMusicBtn.addEventListener("click", () => {
          const items = collectRecentMusicSnapshot();
          if (!items.length) {
            return;
          }
          writeRecentMusic([]);
          renderRecentMusic([]);
        });
      }
    }

    if (showRecent && recentNode) {
      const recentSkeletonCount = dashboardSkeletonCount(DASHBOARD_RECENT_COUNT_KEY, 3);
      recentNode.innerHTML = Array.from({ length: recentSkeletonCount }).map(() => '<article class="nebula-dashboard-item nebula-dashboard-item-skeleton"><div class="nebula-dashboard-thumb"><div class="nebula-skeleton-block"></div></div></article>').join("");
    }
    if (showFavorites && favoritesNode) {
      const favoritesSkeletonCount = dashboardSkeletonCount(DASHBOARD_FAVORITES_COUNT_KEY, 4);
      favoritesNode.innerHTML = Array.from({ length: favoritesSkeletonCount }).map(() => '<article class="nebula-dashboard-item nebula-dashboard-item-skeleton"><div class="nebula-dashboard-thumb"><div class="nebula-skeleton-block"></div></div></article>').join("");
    }
    if (showStats && statsNode) {
      statsNode.innerHTML = `
        ${Array.from({ length: 4 }).map(() => '<article class="nebula-stat-card nebula-stat-card-skeleton"><div class="nebula-skeleton-line"></div><div class="nebula-skeleton-line nebula-skeleton-line-wide"></div></article>').join("")}
      `;
    }

    try {
      let sourceDocs = [];
      try {
        const snap = await firestore.collectionGroup("players").where("uid", "==", user.uid).limit(120).get();
        sourceDocs = snap.docs;
      } catch (_queryError) {
        sourceDocs = [];
      }

      if (!sourceDocs.length) {
        try {
          const statsSnap = await firestore.collection("gameStats").orderBy("updatedAt", "desc").limit(220).get();
          const playerDocs = await Promise.all(statsSnap.docs.map(async (statsDoc) => {
            try {
              const playerDoc = await statsDoc.ref.collection("players").doc(user.uid).get();
              return playerDoc.exists ? playerDoc : null;
            } catch (_playerError) {
              return null;
            }
          }));
          sourceDocs = playerDocs.filter(Boolean);
        } catch (_fallbackError) {
          sourceDocs = [];
        }
      }

      const list = sourceDocs.map((doc) => {
        const data = doc.data() || {};
        const parentStats = doc.ref && doc.ref.parent ? doc.ref.parent.parent : null;
        const parentGameId = parentStats ? String(parentStats.id || "") : "";
        const fallbackPath = decodeGamePathFromId(parentGameId);
        return {
          docPath: doc.ref.path,
          gameName: String(data.gameName || "Unknown game"),
          gameImage: String(data.gameImage || ""),
          gamePath: String(data.gamePath || data.activeGamePath || fallbackPath || ""),
          sourceBase: String(data.sourceBase || ""),
          clickCount: Number(data.clickCount || 0),
          rating: Number(data.rating || 0),
          isFavorite: Boolean(data.isFavorite),
          lastPlayedAtMs: toMillis(data.lastPlayedAt),
          lastRatedAtMs: toMillis(data.lastRatedAt)
        };
      });

      const recent = list
        .filter((item) => item.clickCount > 0)
        .sort((a, b) => b.lastPlayedAtMs - a.lastPlayedAtMs)
        .slice(0, 6);

      const favorites = list
        .filter((item) => item.isFavorite)
        .sort((a, b) => b.lastPlayedAtMs - a.lastPlayedAtMs)
        .slice(0, 8);

      localStorage.setItem(DASHBOARD_RECENT_COUNT_KEY, String(recent.length));
      localStorage.setItem(DASHBOARD_FAVORITES_COUNT_KEY, String(favorites.length));

      const totalPlays = list.reduce((sum, item) => sum + Math.max(0, item.clickCount), 0);
      const gamesPlayed = list.filter((item) => item.clickCount > 0).length;
      const thumbsUpGiven = list.filter((item) => item.rating === 1).length;
      const thumbsDownGiven = list.filter((item) => item.rating === -1).length;

      function tileMarkup(item, favoriteMode) {
        const imageMarkup = item.gameImage
          ? `
            <div class="nebula-dashboard-thumb-backdrop" style="background-image:url('${escapeHtml(item.gameImage)}');"></div>
            <img src="${escapeHtml(item.gameImage)}" alt="${escapeHtml(item.gameName)}" loading="lazy" decoding="async">
          `
          : "<div class=\"nebula-dashboard-fallback\"><i class=\"fa-solid fa-gamepad\"></i></div>";
        const removeFavorite = favoriteMode
          ? `<button type="button" class="nebula-dashboard-remove-favorite" data-remove-favorite="1" data-game-path="${escapeHtml(item.gamePath)}" data-source-base="${escapeHtml(item.sourceBase)}" aria-label="Remove from favorites"><i class="fa-solid fa-trash"></i></button>`
          : "";
        const removeRecent = !favoriteMode
          ? `<button type="button" class="nebula-dashboard-remove-favorite" data-remove-recent="1" data-doc-path="${escapeHtml(item.docPath)}" aria-label="Remove from recently played"><i class="fa-solid fa-trash"></i></button>`
          : "";
        return `
          <a href="/games" class="nav-link nebula-dashboard-item" data-game-path="${escapeHtml(item.gamePath)}" data-source-base="${escapeHtml(item.sourceBase)}">
            <div class="nebula-dashboard-thumb">
              ${imageMarkup}
              <div class="nebula-dashboard-meta">
                <h3>${escapeHtml(item.gameName)}</h3>
                <p>Plays: ${item.clickCount}</p>
              </div>
              ${removeFavorite}
              ${removeRecent}
            </div>
          </a>
        `;
      }

      if (showRecent && recentNode) {
        recentNode.innerHTML = recent.length ? recent.map((item) => tileMarkup(item, false)).join("") : '<p class="nebula-dashboard-empty">No recent games yet.</p>';
      }
      if (showFavorites && favoritesNode) {
        favoritesNode.innerHTML = favorites.length ? favorites.map((item) => tileMarkup(item, true)).join("") : '<p class="nebula-dashboard-empty">No favorites yet. Star games in Games.</p>';
      }

      if (showStats && statsNode) {
        statsNode.innerHTML = `
        <article class="nebula-stat-card"><h3>Total Plays</h3><p>${totalPlays}</p></article>
        <article class="nebula-stat-card"><h3>Games Played</h3><p>${gamesPlayed}</p></article>
        <article class="nebula-stat-card"><h3>Thumbs Up Given</h3><p>${thumbsUpGiven}</p></article>
        <article class="nebula-stat-card"><h3>Thumbs Down Given</h3><p>${thumbsDownGiven}</p></article>
      `;
      }

      if (showFavorites && favoritesNode) {
        favoritesNode.querySelectorAll("[data-remove-favorite='1']").forEach((button) => {
          button.addEventListener("click", async (event) => {
            event.preventDefault();
            event.stopPropagation();
            const path = button.getAttribute("data-game-path") || "";
            const sourceBase = button.getAttribute("data-source-base") || "";
            if (!path || !window.NebulaGames || typeof window.NebulaGames.setFavoriteByPath !== "function") {
              return;
            }
            try {
              await window.NebulaGames.setFavoriteByPath(path, sourceBase, false);
              const card = button.closest(".nebula-dashboard-item");
              if (card) {
                card.remove();
              }
              const remainingFavorites = favoritesNode.querySelectorAll(".nebula-dashboard-item").length;
              localStorage.setItem(DASHBOARD_FAVORITES_COUNT_KEY, String(remainingFavorites));
              if (!favoritesNode.querySelector(".nebula-dashboard-item")) {
                favoritesNode.innerHTML = '<p class="nebula-dashboard-empty">No favorites yet. Star games in Games.</p>';
              }
            } catch (_error) {
            }
          });
        });
      }

      if (showRecent && recentNode) {
        recentNode.querySelectorAll("[data-remove-recent='1']").forEach((button) => {
          button.addEventListener("click", async (event) => {
            event.preventDefault();
            event.stopPropagation();
            const docPath = String(button.getAttribute("data-doc-path") || "").trim();
            if (!docPath) {
              return;
            }
            try {
              await firestore.doc(docPath).set({
                clickCount: 0,
                lastPlayedAt: firebase.firestore.FieldValue.delete(),
                activeSession: firebase.firestore.FieldValue.delete(),
                activeGamePath: firebase.firestore.FieldValue.delete(),
                activeAt: firebase.firestore.FieldValue.delete(),
              }, { merge: true });
              const card = button.closest(".nebula-dashboard-item");
              if (card) {
                card.remove();
              }
              const clearRecentBtn = document.getElementById("dashboard-clear-recent");
              const hasCards = Boolean(recentNode.querySelector(".nebula-dashboard-item"));
              const remainingRecent = recentNode.querySelectorAll(".nebula-dashboard-item").length;
              localStorage.setItem(DASHBOARD_RECENT_COUNT_KEY, String(remainingRecent));
              if (clearRecentBtn) {
                clearRecentBtn.disabled = !hasCards;
              }
              if (!hasCards) {
                recentNode.innerHTML = '<p class="nebula-dashboard-empty">No recent games yet.</p>';
              }
            } catch (_error) {
            }
          });
        });
      }

      const clearRecentBtn = document.getElementById("dashboard-clear-recent");
      if (clearRecentBtn) {
        clearRecentBtn.disabled = !recent.length;
        clearRecentBtn.addEventListener("click", async () => {
          if (!recent.length) {
            return;
          }
          const updates = recent.map((item) => firestore.doc(item.docPath).set({
            clickCount: 0,
            lastPlayedAt: firebase.firestore.FieldValue.delete(),
            activeSession: firebase.firestore.FieldValue.delete(),
            activeGamePath: firebase.firestore.FieldValue.delete(),
            activeAt: firebase.firestore.FieldValue.delete(),
          }, { merge: true }).catch(() => null));
          await Promise.all(updates);
          recentNode.innerHTML = '<p class="nebula-dashboard-empty">No recent games yet.</p>';
          localStorage.setItem(DASHBOARD_RECENT_COUNT_KEY, "0");
          clearRecentBtn.disabled = true;
        });
      }
    } catch (_error) {
      if (showRecent && recentNode) {
        recentNode.innerHTML = '<p class="nebula-dashboard-empty">Could not load recent games.</p>';
      }
      if (showFavorites && favoritesNode) {
        favoritesNode.innerHTML = '<p class="nebula-dashboard-empty">Could not load favorites.</p>';
      }
      if (showStats && statsNode) {
        statsNode.innerHTML = '<p class="nebula-dashboard-empty">Could not load stats.</p>';
      }
    }
  }

  function syncLockedState(path) {
    updateHomeNavLabel();
    const locked = !isLoggedIn();
    document.body.classList.toggle("auth-locked", locked);
    document.body.setAttribute("data-auth-lock", locked ? "on" : "off");
    document.querySelectorAll(".sidebar .nav-link").forEach((link) => {
      const href = link.getAttribute("href") || "";
      const disabled = locked && href !== "/";
      link.classList.toggle("auth-disabled", disabled);
      if (disabled) {
        link.setAttribute("aria-disabled", "true");
      } else {
        link.removeAttribute("aria-disabled");
      }
    });
    if (locked && path !== "/") {
      showMessagePopup("Log in or sign up to access that page.", "Locked");
    }
  }

  function guardedPath(path) {
    const normalized = String(path || "/");
    const action = getActionParams();
    if (action) {
      if (window.location.pathname !== "/") {
        window.history.replaceState({}, "", `/${window.location.search || ""}`);
      }
      return "/";
    }
    if (!isLoggedIn() && normalized !== "/") {
      if (window.location.pathname !== "/") {
        window.history.replaceState({}, "", `/${window.location.search || ""}`);
      }
      return "/";
    }
    return normalized;
  }

