  function openVerifyEmailModal(initialStatusText, initialStatusOk) {
    showModal("Verify Email", `
      <div class="nebula-auth-form">
        <p>We sent a verification email. Verify within five minutes to continue.</p>
        <p>Time left: <strong id="verify-countdown">05:00</strong></p>
        <p id="verify-status" class="nebula-status"></p>
        <p><b>Note to Gmail users:</b> It will mark the email as spam, so check your spam folder. If you still don't see it, check "All mail", or try resending.</p>
        <button id="verify-refresh" type="button" class="nebula-btn nebula-btn-primary">I Verified</button>
        <button id="verify-resend" type="button" class="nebula-btn nebula-btn-muted" disabled>Resend Email</button>
      </div>
    `, "verify-email");

    const countdown = document.getElementById("verify-countdown");
    const resendBtn = document.getElementById("verify-resend");
    const refreshBtn = document.getElementById("verify-refresh");

    if (initialStatusText) {
      setStatus("verify-status", String(initialStatusText), Boolean(initialStatusOk));
    }

    function refreshTimer() {
      const now = Date.now();
      const untilDeadline = Math.max(0, state.verifyDeadline - now);
      const untilResend = Math.max(0, state.resendAllowedAt - now);
      if (countdown) {
        countdown.textContent = toTimeText(untilDeadline);
      }
      if (resendBtn) {
        resendBtn.disabled = untilResend > 0;
        resendBtn.textContent = untilResend > 0 ? `Resend Email (${toTimeText(untilResend)})` : "Resend Email";
      }
      if (untilDeadline <= 0) {
        setStatus("verify-status", "Verification window expired. Resend and verify again.", false);
      }
    }

    refreshTimer();
    if (state.verifyTimerId) {
      window.clearInterval(state.verifyTimerId);
    }
    state.verifyTimerId = window.setInterval(refreshTimer, 1000);

    if (resendBtn) {
      resendBtn.addEventListener("click", async () => {
        const user = currentUser();
        if (!user) {
          setStatus("verify-status", "No active user.", false);
          return;
        }
        if (Date.now() < state.resendAllowedAt) {
          return;
        }
        try {
          const verifySend = await sendVerificationEmailWithFallback(user);
          if (!verifySend.ok) {
            const code = authErrorCode(verifySend.error);
            if (code === "auth/too-many-requests") {
              state.resendAllowedAt = Date.now() + VERIFY_TOO_MANY_REQUESTS_BACKOFF_MS;
              refreshTimer();
            }
            setStatus("verify-status", detailedAuthStatus(verifySend.error, "verify-email-send"), false);
            return;
          }
          state.verifyDeadline = Date.now() + VERIFICATION_WINDOW_MS;
          state.resendAllowedAt = Date.now() + VERIFICATION_WINDOW_MS;
          setStatus("verify-status", "Verification email resent.", true);
          refreshTimer();
        } catch (error) {
          setStatus("verify-status", detailedAuthStatus(error, "verify-email-send"), false);
        }
      });
    }

    if (refreshBtn) {
      refreshBtn.addEventListener("click", async () => {
        const user = currentUser();
        if (!user) {
          setStatus("verify-status", "No active user.", false);
          return;
        }
        try {
          await user.reload();
          const updatedUser = currentUser();
          if (Date.now() > state.verifyDeadline) {
            setStatus("verify-status", "Verification window expired. Resend and try again.", false);
            return;
          }
          if (!updatedUser || !updatedUser.emailVerified) {
            setStatus("verify-status", "Email is not verified yet.", false);
            return;
          }
          openUsernameModal();
        } catch (error) {
          setStatus("verify-status", friendlyAuthMessage(error, "verify-email-check"), false);
        }
      });
    }
  }

