  async function changeUsernameInSettings() {
    const user = currentUser();
    if (!user) {
      setStatus("settings-username-status", "You must be logged in.", false);
      return;
    }

    const input = document.getElementById("settings-username-input");
    const username = String(input && input.value ? input.value : "").trim();
    if (!/^[A-Za-z0-9_.-]{3,24}$/.test(username)) {
      setStatus("settings-username-status", "Use 3-24 characters: letters, numbers, underscore, period, or dash.", false);
      return;
    }

    if (String(user.displayName || "").trim().toLowerCase() === username.toLowerCase()) {
      setStatus("settings-username-status", "That is already your username.", false);
      return;
    }

    try {
      const firestore = db();
      if (firestore) {
        const userDoc = await firestore.collection(USER_DOC_COLLECTION).doc(user.uid).get();
        if (userDoc.exists) {
          const userData = userDoc.data() || {};
          const currentHash = String(userData.usernameHash || "");
          const desiredHash = await hashText(username.toLowerCase());
          const changedAtMs = toMillis(userData.usernameChangedAt);
          if (currentHash && currentHash !== desiredHash && changedAtMs) {
            const nextAllowedMs = changedAtMs + USERNAME_CHANGE_COOLDOWN_MS;
            if (Date.now() < nextAllowedMs) {
              setStatus("settings-username-status", `Wait until ${new Date(nextAllowedMs).toLocaleString()} to change your username again.`, false);
              return;
            }
          }
        }
      }

      await reserveUsername(user, username, { enforceCooldown: true });
      await user.updateProfile({ displayName: username });
      await ensureUserDoc(user, username);
      setStatus("settings-username-status", "Username updated.", true);
      const currentUsername = document.getElementById("settings-current-username");
      if (currentUsername) {
        currentUsername.textContent = `Current username: ${username}`;
      }
      const nextAllowed = document.getElementById("settings-next-username-change");
      const nextAllowedMs = Date.now() + USERNAME_CHANGE_COOLDOWN_MS;
      if (nextAllowed) {
        nextAllowed.textContent = `Next allowed change: ${new Date(nextAllowedMs).toLocaleString()}`;
      }
    } catch (error) {
      setStatus("settings-username-status", error && error.message ? error.message : "Could not update username.", false);
    }
  }

